protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Blog>(b =>
    {
        // EF9 renamed the default discriminator from "Discriminator" to "$type".
        // Keep the old name so existing documents are still matched.
        b.HasDiscriminator<string>("Discriminator");

        // EF9 maps the key property directly to the JSON "id" field.
        // Existing documents store the key in a separate "Id" JSON property
        // and use a shadow "__id" field (format "Blog|<key>") as the Cosmos id.
        b.Property(e => e.Id).ToJsonProperty("Id");
        b.Property<string>("__id").ToJsonProperty("id");

        // EF9 throws on HasIndex for the Cosmos provider — removed.
    });
}

